export const FR2_POSTS: FR2Post[] = [

  // ═══════════════════════════════════════════════════════════════════════════
  // 1. fr-36 — Infirmières formées à l'étranger (~1 300 mots)
  // ═══════════════════════════════════════════════════════════════════════════
  {
    ...FR2_TOPICS[5],
    wordCount: 1300,
    sections: [
      { heading: "intro", body: `Chaque année, des milliers d'infirmières et d'infirmiers formés à l'étranger (IFE) s'installent au Canada avec l'ambition de poursuivre leur carrière en soins infirmiers. Le système de santé canadien a désespérément besoin de ces professionnelles qualifiées — mais le parcours pour obtenir le titre d'infirmière auxiliaire autorisée (IAA) exige de la persévérance, de la stratégie et une compréhension claire des exigences.\n\nLe REx-PN (examen réglementaire pour l'admission à la profession d'infirmière auxiliaire) est l'étape cruciale qui sépare les IFE de leur permis de pratique au Canada. Ce guide a été conçu spécifiquement pour vous : une professionnelle qualifiée dans votre pays d'origine qui doit naviguer un système réglementaire différent, souvent dans une langue seconde, tout en s'adaptant à une nouvelle vie.\n\nQue vous soyez au Québec, en Ontario ou ailleurs au Canada, ce guide couvre tout ce que vous devez savoir.\n\n[Essayez des questions gratuites](${lnk.questions}) pour évaluer votre niveau actuel avant de planifier votre préparation.` },
      { heading: "Le parcours réglementaire pour les IFE au Canada", body: `Le chemin vers le REx-PN varie selon la province, mais le processus général comporte les étapes suivantes :\n\n**1. Évaluation des titres de compétences**\nLa première étape consiste à faire évaluer vos diplômes et votre expérience par l'organisme réglementaire provincial. Au Québec, c'est l'Ordre des infirmières et infirmiers auxiliaires du Québec (OIIAQ). En Ontario, le College of Nurses of Ontario (CNO) gère ce processus.\n\nL'évaluation détermine si votre formation est suffisamment équivalente au programme canadien ou si vous devez compléter des cours supplémentaires.\n\n**2. Programmes passerelles (bridging)**\nSelon les lacunes identifiées, vous pourriez devoir suivre un programme passerelle. Ces programmes couvrent :\n- Le champ de pratique spécifique des IAA au Canada\n- La pharmacologie canadienne (noms commerciaux, dosages, pratiques de prescription)\n- Les normes de pratique canadiennes et le cadre juridique\n- Les compétences cliniques pratiques dans un contexte canadien\n\nLa durée varie de quelques mois à un an selon votre formation initiale. Certains collèges offrent des programmes accélérés pour les IFE ayant une expérience substantielle.\n\n**3. Admissibilité au REx-PN**\nUne fois votre programme terminé (ou si votre formation est jugée équivalente sans programme passerelle), vous pouvez vous inscrire au REx-PN via Pearson VUE. Le processus d'inscription est le même que pour les diplômées canadiennes.\n\nPour le Québec spécifiquement, consultez notre guide détaillé sur [l'inscription au REx-PN au Québec](${lnk.lessons}).` },
      { heading: "Les défis uniques des IFE pour le REx-PN", body: `Les IFE font face à des obstacles que les diplômées canadiennes n'ont pas :\n\n**Différences de champ de pratique**\nDans beaucoup de pays, le rôle d'infirmière auxiliaire n'existe pas — ou le champ de pratique est très différent. Vous êtes peut-être une infirmière bachelière dans votre pays d'origine, mais le REx-PN teste le champ de pratique spécifique des IAA au Canada, qui est plus limité.\n\nExemple concret : dans plusieurs pays, l'infirmière peut initier des traitements IV de façon autonome. Au Canada, une IAA peut administrer des médicaments IV dans certaines provinces, mais toujours sous supervision ou avec des restrictions. Le REx-PN teste cette nuance.\n\n**Terminologie en français ou en anglais canadien**\nMême si vous parlez français ou anglais couramment, la terminologie médicale canadienne peut différer de celle de votre pays. Les noms commerciaux des médicaments, les abréviations et même certains termes cliniques peuvent varier.\n\nConseil : étudiez les [médicaments à haut risque](${lnk.lesson("high-alert-medications-gold")}) en utilisant les noms commerciaux canadiens dès le début de votre préparation.\n\n**Le format adaptatif (TAO)**\nLe test adaptatif par ordinateur peut être nouveau pour vous. Le REx-PN ajuste la difficulté des questions en temps réel selon vos réponses. Ce format est très différent des examens à format fixe courants dans d'autres pays.\n\nPratiquez avec des [examens adaptatifs simulés](${lnk.cat}) pour vous familiariser avec ce format avant le jour de l'examen.\n\n**La culture infirmière canadienne**\nLes questions du REx-PN reflètent les valeurs du système de santé canadien : autonomie du patient, consentement éclairé, approche centrée sur la personne et collaboration interprofessionnelle. Si vous venez d'un système plus hiérarchique, certaines réponses correctes au REx-PN pourraient vous surprendre.` },
      { heading: "Plan d'étude adapté pour les IFE : 8 à 12 semaines", body: `Ce plan tient compte du fait que vous devez non seulement réviser le contenu clinique, mais aussi vous adapter au contexte canadien.\n\n**Semaines 1-3 : Fondations canadiennes**\n- Étudiez le champ de pratique des IAA en détail (OIIAQ ou CNO selon votre province)\n- Révisez les [questions de délégation et champ de pratique](${lnk.lessons}) — c'est votre plus grand défi en tant qu'IFE\n- Faites 20 [questions pratiques](${lnk.questions}) par jour avec lecture attentive des justifications\n- Familiarisez-vous avec la terminologie médicale canadienne (noms commerciaux des médicaments)\n\n**Semaines 4-6 : Contenu clinique à haut rendement**\n- [Jugement clinique et priorisation](${lnk.lesson("clinical-judgment-prioritization-gold")}) — la compétence fondamentale du REx-PN\n- [Médicaments à haut risque](${lnk.lesson("high-alert-medications-gold")}) — insuline, héparine, warfarine, digoxine\n- [Reconnaissance précoce de la sepsie](${lnk.lesson("sepsis-early-recognition-gold")})\n- [Liquides et électrolytes](${lnk.lesson("fluids-electrolytes-emergencies-gold")})\n- Augmentez à 30-40 questions par jour\n\n**Semaines 7-9 : Consolidation et examens adaptatifs**\n- Passez votre premier [examen adaptatif complet](${lnk.cat})\n- Identifiez vos 3 sujets les plus faibles et consacrez-y 2 jours chacun\n- Continuez 30-40 questions par jour avec accent sur les justifications\n- Révisez les [questions canadiennes à haut rendement](${lnk.lesson("canadian-rpn-high-yield-gold")})\n\n**Semaines 10-12 : Simulation et affinage**\n- Un examen adaptatif complet par semaine\n- Ciblez les questions que vous ratez systématiquement\n- Révisez la gestion du temps pendant l'examen\n- La dernière semaine : allégez l'étude, dormez bien, préparez votre routine du jour de l'examen\n\n[Évaluez votre niveau](${lnk.cat}) dès maintenant avec un examen adaptatif gratuit pour déterminer votre point de départ.` },
      { heading: "Sujets à haut rendement spécifiques pour les IFE", body: `Selon les données de performance des IFE, voici les sujets qui causent le plus de difficultés — et qui sont les plus rentables à maîtriser :\n\n**1. Délégation et champ de pratique (le piège #1)**\nLes IFE surestiment souvent ce qu'une IAA peut faire au Canada. Le REx-PN teste si vous savez ce que vous NE pouvez PAS faire, autant que ce que vous pouvez faire. Étudiez les limites du champ de pratique avant tout.\n\n**2. Communication thérapeutique**\nLes réponses thérapeutiques au REx-PN reflètent la culture canadienne de soins centrés sur le patient. « Qu'est-ce qui vous préoccupe? » est souvent la meilleure réponse — pas « Je vais appeler le médecin ».\n\n**3. Consentement éclairé et droits du patient**\nLe cadre juridique canadien concernant le consentement, la confidentialité et les directives anticipées est spécifique. Maîtrisez-le.\n\n**4. Priorisation ABC et Maslow**\nLes cadres de priorisation (Airway-Breathing-Circulation et la hiérarchie de Maslow) sont universels, mais le REx-PN les applique d'une façon qui peut être différente de votre formation initiale.\n\n**5. Pharmacologie canadienne**\nLes noms commerciaux des médicaments au Canada sont souvent différents de ceux de votre pays. Faites une liste comparative et étudiez-la régulièrement.` },
      { heading: "Ressources et soutien pour les IFE", body: `**Ressources institutionnelles :**\n- OIIAQ (Québec) : programmes d'intégration et mentorat\n- CNO (Ontario) : guide d'orientation pour les IFE\n- Services d'immigration : certaines provinces offrent des subventions pour les programmes passerelles\n\n**Soutien communautaire :**\n- Associations d'infirmières immigrantes dans votre région\n- Groupes Facebook et WhatsApp de préparation au REx-PN pour les IFE\n- Mentorat par des IAA qui étaient elles-mêmes des IFE\n\n**Soutien linguistique :**\n- Cours de français ou d'anglais médical offerts par certains collèges\n- Glossaires de terminologie médicale canadienne\n- Pratiquez en [faisant des questions en français](${lnk.questions}) pour renforcer votre vocabulaire clinique\n\n[Débloquez l'accès complet](${lnk.pricing}) pour accéder à plus de 2 000 questions pratiques avec justifications détaillées, des leçons structurées et des examens adaptatifs conçus pour le REx-PN canadien.` },
      { heading: "Vous avez traversé des océans — vous pouvez traverser cet examen", body: `Être une IFE au Canada n'est pas un désavantage — c'est une preuve de courage et de détermination. Vous avez déjà démontré votre résilience en quittant votre pays, en apprenant une nouvelle langue et en vous adaptant à une nouvelle culture.\n\nLe REx-PN est un défi, oui. Mais c'est un défi que des milliers d'IFE ont relevé avec succès avant vous. Avec un plan d'étude structuré, des questions pratiques de qualité et une compréhension claire du champ de pratique canadien, vous pouvez y arriver.\n\nCommencez dès aujourd'hui. Pas demain. Pas lundi prochain. Maintenant.\n\n[Essayez des questions gratuites](${lnk.questions}) pour savoir où vous en êtes et créer votre plan d'étude personnalisé.` },
    ],
    faq: [
      { question: "Combien de temps faut-il à une IFE pour se préparer au REx-PN?", answer: "Cela dépend de votre formation et de votre expérience. En moyenne, 8 à 12 semaines de préparation structurée après avoir complété les exigences de formation complémentaire. Si votre champ de pratique dans votre pays d'origine était très différent de celui des IAA au Canada, prévoyez 12 semaines." },
      { question: "Dois-je refaire toute ma formation infirmière au Canada?", answer: "Non. Le processus de reconnaissance des acquis (RAC) évalue votre formation et détermine les cours complémentaires nécessaires. Beaucoup d'IFE n'ont qu'un programme passerelle partiel à compléter, pas un programme complet." },
      { question: "Puis-je passer le REx-PN en anglais si ma formation complémentaire était en français?", answer: "Oui. Vous pouvez choisir la langue de l'examen indépendamment de la langue de votre formation. Choisissez la langue dans laquelle vous maîtrisez le mieux la terminologie médicale." },
    ],
    references: [
      { text: "Ordre des infirmières et infirmiers auxiliaires du Québec (OIIAQ). « Admission par équivalence — Infirmières formées à l'étranger. » oiiaq.org, 2025." },
      { text: "College of Nurses of Ontario (CNO). « Internationally Educated Nurses — Registration Requirements. » cno.org, 2025." },
      { text: "Gouvernement du Canada. « Reconnaissance des titres de compétences étrangers — Profession infirmière. » canada.ca, 2025." },
    ],
  },

  // ═══════════════════════════════════════════════════════════════════════════
  // 2. fr-46 — Soins rénaux au REx-PN (~1 250 mots)
  // ═══════════════════════════════════════════════════════════════════════════
  {
    ...FR2_TOPICS[15],
    wordCount: 1250,
    sections: [
      { heading: "intro", body: `Les questions sur les soins rénaux sont parmi les plus redoutées au REx-PN — et pour cause. Elles combinent la physiopathologie, la gestion des liquides et des électrolytes, la pharmacologie et le jugement clinique en un seul scénario complexe.\n\nPourtant, une fois que vous comprenez la logique qui relie l'insuffisance rénale chronique (IRC), l'insuffisance rénale aiguë (IRA) et la dialyse, ces questions deviennent prévisibles et systématiques. Ce guide couvre tout ce qu'une IAA doit savoir sur les soins rénaux pour le REx-PN.\n\nLes soins rénaux sont étroitement liés à la gestion des [liquides et électrolytes](${lnk.lesson("fluids-electrolytes-emergencies-gold")}) — révisez ce sujet en parallèle pour une compréhension complète.\n\n[Essayez des questions gratuites](${lnk.questions}) sur les soins rénaux pour évaluer votre niveau avant de continuer.` },
      { heading: "Insuffisance rénale chronique (IRC) : les 5 stades expliqués", body: `L'IRC est une détérioration progressive et irréversible de la fonction rénale. Le REx-PN attend que vous compreniez les stades et les implications pour les soins infirmiers.\n\n**Stade 1 (DFG ≥ 90 mL/min) :** Dommage rénal avec fonction normale. Le patient peut être asymptomatique. L'IAA surveille la pression artérielle et les analyses de laboratoire.\n\n**Stade 2 (DFG 60-89) :** Diminution légère. Enseignement sur la diète (restriction sodique modérée), surveillance des facteurs de risque.\n\n**Stade 3a/3b (DFG 30-59) :** Diminution modérée. Apparition possible d'anémie, déséquilibres phosphocalciques. Référence en néphrologie. L'IAA surveille les laboratoires : créatinine, urée, potassium, phosphore, calcium.\n\n**Stade 4 (DFG 15-29) :** Diminution sévère. Préparation à la thérapie de remplacement rénal. Enseignement sur les options de dialyse. Restriction stricte des protéines, du potassium et du phosphore.\n\n**Stade 5 (DFG < 15) :** Insuffisance rénale terminale (IRT). Dialyse ou greffe nécessaire. Symptômes urémiques : nausées, prurit, confusion, souffle urémique.\n\n**Ce que le REx-PN teste :**\n- Reconnaître les signes et symptômes de progression\n- Interventions appropriées au stade (enseignement, surveillance, préparation à la dialyse)\n- Valeurs de laboratoire anormales et leurs implications\n- Modifications diététiques par stade` },
      { heading: "Hémodialyse vs dialyse péritonéale : rôle de l'IAA", body: `Le REx-PN teste votre compréhension des deux types de dialyse et le rôle spécifique de l'IAA.\n\n**Hémodialyse (HD)**\n- Le sang est filtré à travers un filtre externe (dialyseur)\n- Accès vasculaire : fistule artérioveineuse (FAV), greffon ou cathéter veineux central\n- Habituellement 3 séances par semaine, 3-4 heures chacune\n\n*Rôle de l'IAA :*\n- Surveiller les signes vitaux avant, pendant et après le traitement\n- Évaluer l'accès vasculaire : thrill (vibration palpable) et bruit (son audible au stéthoscope) — leur ABSENCE est une urgence\n- NE PAS prendre la PA ni faire de ponction veineuse au bras de la FAV\n- Surveiller les complications : hypotension, crampes, saignement au site d'accès\n- Peser le patient avant et après chaque séance (la différence = liquide retiré)\n\n**Dialyse péritonéale (DP)**\n- Le péritoine sert de membrane de filtration\n- Dialysat infusé et drainé via un cathéter abdominal\n- Peut être faite à domicile (DPCA ou DPA)\n\n*Rôle de l'IAA :*\n- Technique stérile rigoureuse lors de la manipulation du cathéter\n- Surveiller l'effluent : doit être clair et jaune pâle — un effluent trouble = péritonite possible (URGENT)\n- Surveiller les signes de péritonite : douleur abdominale, fièvre, effluent trouble\n- Enseignement au patient sur la technique à domicile\n\n**Piège REx-PN classique :** Une question sur un patient en hémodialyse qui a une FAV au bras gauche. L'infirmière de l'équipe veut prendre la PA au bras gauche. Que faites-vous? Réponse : REFUSER et expliquer — la PA au bras de la FAV peut l'endommager.\n\n[Révisez les interventions d'urgence liées aux liquides et électrolytes](${lnk.lesson("fluids-electrolytes-emergencies-gold")}) — les déséquilibres électrolytiques sont la complication la plus fréquente de la dialyse.` },
      { heading: "Insuffisance rénale aiguë (IRA) : reconnaissance et phases", body: `L'IRA est une détérioration rapide et potentiellement réversible de la fonction rénale. Le REx-PN teste votre capacité à la reconnaître tôt et à intervenir rapidement.\n\n**Les 3 types d'IRA :**\n\n*Prérénale (la plus fréquente) :* Diminution du débit sanguin vers les reins. Causes : déshydratation, hémorragie, insuffisance cardiaque, choc septique. Le rein est intact mais ne reçoit pas assez de sang.\n\n*Intrarénale :* Dommage direct au rein. Causes : néphrotoxicité (aminoglycosides, produits de contraste iodé), glomérulonéphrite, nécrose tubulaire aiguë.\n\n*Postrénale :* Obstruction de l'écoulement urinaire. Causes : calculs rénaux bilatéraux, hypertrophie prostatique, tumeur.\n\n**Les 3 phases de l'IRA :**\n\n*Phase oligurique (1-2 semaines) :*\n- Débit urinaire < 400 mL/24 h\n- Rétention de liquides → œdème, hypertension, surcharge liquidienne\n- ↑ Potassium (DANGER : arythmies cardiaques), ↑ créatinine, ↑ urée\n- Surveillance étroite du bilan des ingesta et excreta (I&E)\n\n*Phase diurétique (1-3 semaines) :*\n- Les reins commencent à récupérer et produisent de grandes quantités d'urine\n- Risque de déshydratation et de pertes électrolytiques\n- Remplacement liquidien et électrolytique selon les prescriptions\n\n*Phase de récupération (mois) :*\n- Retour graduel à la fonction rénale normale\n- Surveillance continue des valeurs de laboratoire\n\n**Interventions de l'IAA en IRA :**\n- Bilan strict des I&E — le plus important\n- Poids quotidien (même heure, même balance, même vêtements)\n- Surveillance des signes vitaux, y compris la PA et la saturation\n- Reconnaître les signes d'[hyperkaliémie](${lnk.lesson("fluids-electrolytes-emergencies-gold")}) : faiblesse musculaire, ECG anormal, paresthésies\n- Administrer les médicaments selon les prescriptions (diurétiques en phase oligurique)\n- Éviter les néphrotoxiques (vérifier les médicaments avec le pharmacien)` },
      { heading: "Gestion des liquides et électrolytes en soins rénaux", body: `Les déséquilibres liquidiens et électrolytiques sont au cœur des soins rénaux et sont fréquemment testés au REx-PN.\n\n**Hyperkaliémie (K+ > 5,0 mmol/L) — La menace #1**\nLes reins sont le principal régulateur du potassium. Quand ils défaillent, le potassium s'accumule et peut provoquer des arythmies mortelles.\n- Signes : faiblesse musculaire, paresthésies, nausées, pouls irrégulier\n- ECG : ondes T pointues → complexes QRS élargis → fibrillation ventriculaire\n- Interventions : gluconate de calcium IV (protège le cœur), insuline + glucose (fait entrer le K+ dans les cellules), résine échangeuse (Kayexalate), dialyse d'urgence\n\n**Surcharge liquidienne**\n- Les reins ne peuvent pas éliminer l'excès de liquide\n- Signes : œdème (commence aux chevilles), dyspnée, crépitants pulmonaires, distension des veines jugulaires, gain de poids rapide (> 1 kg/jour = ~ 1 L de rétention)\n- Interventions : restriction liquidienne, diurétiques si prescrits, position semi-Fowler, surveillance de l'oxymétrie\n\n**Déséquilibre phosphocalcique**\n- IRC → ↑ phosphore → ↓ calcium (relation inverse)\n- ↓ Calcium chronique → fragilité osseuse (ostéodystrophie rénale)\n- Interventions : chélateurs de phosphore avec les repas, suppléments de vitamine D active, restriction du phosphore alimentaire\n\n**Anémie rénale**\n- Les reins produisent l'érythropoïétine (EPO). IRC → ↓ EPO → ↓ production de globules rouges\n- Interventions : érythropoïétine recombinante (époetin alfa), suppléments de fer, surveillance de l'hémoglobine\n\nConseil d'examen : au REx-PN, quand une question mentionne un patient en IRC avec une faiblesse musculaire soudaine, pensez IMMÉDIATEMENT à l'hyperkaliémie. Vérifiez le potassium et l'ECG avant tout.` },
      { heading: "Pharmacologie et considérations rénales", body: `Le REx-PN teste votre compréhension des médicaments en contexte rénal.\n\n**Médicaments néphrotoxiques à connaître :**\n- Aminoglycosides (gentamicine, tobramycine) : surveiller les taux sériques et la créatinine\n- Anti-inflammatoires non stéroïdiens (AINS) : éviter chez les patients en IRC\n- Produits de contraste iodé : hydratation IV avant et après les examens d'imagerie\n- Vancomycine : ajustement de dose selon la fonction rénale\n\n**Ajustement des doses en insuffisance rénale :**\nLes reins éliminent de nombreux médicaments. Quand la fonction rénale diminue, les médicaments s'accumulent et deviennent toxiques. L'IAA doit :\n- Surveiller les signes de toxicité médicamenteuse\n- Vérifier la créatinine et le DFG avant d'administrer certains médicaments\n- Communiquer avec le pharmacien en cas de doute\n\n**Médicaments fréquents en soins rénaux :**\n- IECA/ARA (énalapril, losartan) : protègent les reins mais peuvent augmenter le potassium — surveillance du K+\n- Diurétiques de l'anse (furosémide) : utilisés en surcharge liquidienne — surveiller la déshydratation et l'hypokaliémie\n- Chélateurs de phosphore (carbonate de calcium, sevelamer) : prendre AVEC les repas\n- EPO (époetin alfa) : surveiller la PA (peut causer de l'hypertension)\n\nRévisez la [pharmacologie à haut risque](${lnk.lesson("high-alert-medications-gold")}) pour une couverture complète des médicaments testés au REx-PN.` },
      { heading: "Stratégie de pratique pour les questions rénales", body: `Les questions rénales au REx-PN sont prévisibles une fois que vous maîtrisez les schémas récurrents :\n\n**Schéma 1 : « Le patient dialysé avec une complication »**\nLe REx-PN vous présentera un patient en dialyse avec un problème (hypotension post-HD, effluent trouble en DP, saignement au site d'accès). L'enjeu est de reconnaître la complication et d'intervenir correctement.\n\n**Schéma 2 : « Les valeurs de laboratoire anormales »**\nUn scénario avec des résultats de labo : potassium élevé, phosphore élevé, calcium bas, créatinine élevée. On vous demande quelle intervention est prioritaire. Presque toujours : traiter l'hyperkaliémie d'abord (danger cardiaque immédiat).\n\n**Schéma 3 : « L'enseignement au patient IRC »**\nQuestions sur les modifications diététiques, les signes d'alerte à enseigner au patient, la surveillance de l'accès vasculaire à domicile.\n\n**Comment pratiquer efficacement :**\n1. Faites 15-20 questions rénales par session avec [NurseNest](${lnk.questions})\n2. Lisez CHAQUE justification — même pour les questions que vous avez bien répondues\n3. Créez un tableau des valeurs de laboratoire rénales avec les plages normales et les interventions\n4. Associez toujours les soins rénaux à la révision des [liquides et électrolytes](${lnk.lesson("fluids-electrolytes-emergencies-gold")}) et du [SCA](${lnk.lesson("acs-stemi-nstemi-ua-gold")}) (l'hyperkaliémie affecte le cœur)\n\n[Évaluez votre niveau](${lnk.cat}) avec un examen adaptatif simulé qui intègre des questions rénales dans un contexte d'examen réaliste.\n\n[Débloquez l'accès complet](${lnk.pricing}) pour accéder à toutes les questions rénales avec justifications détaillées, leçons structurées et suivi de vos progrès.` },
    ],
    faq: [
      { question: "Les soins rénaux représentent quelle proportion du REx-PN?", answer: "Les soins rénaux ne constituent pas une catégorie distincte au REx-PN, mais les questions sur l'insuffisance rénale, la dialyse et les déséquilibres électrolytiques apparaissent fréquemment dans les catégories de médecine-chirurgie et de soins critiques. Estimez 5 à 10 % des questions, souvent intégrées dans des scénarios plus complexes." },
      { question: "Quelles sont les valeurs de laboratoire rénales les plus importantes à mémoriser?", answer: "Créatinine normale : 53-106 µmol/L; urée : 2,5-8,0 mmol/L; potassium : 3,5-5,0 mmol/L; DFG normal : > 90 mL/min. L'hyperkaliémie (K+ > 5,0) est la valeur la plus critique — elle peut provoquer des arythmies mortelles." },
      { question: "Comment distinguer une IRA prérénale d'une IRA intrarénale au REx-PN?", answer: "La clé est la cause sous-jacente. Prérénale : le patient est déshydraté, en hémorragie ou en choc (problème de perfusion). Intrarénale : le patient a reçu un médicament néphrotoxique ou a une glomérulonéphrite (problème du rein lui-même). L'IRA prérénale est réversible avec la restauration du volume; l'intrarénale nécessite un traitement plus long." },
    ],
    references: [
      { text: "Kidney Foundation of Canada. « Insuffisance rénale chronique : stades et traitement. » kidney.ca, 2025." },
      { text: "Association canadienne des infirmières et infirmiers en néphrologie. « Normes de pratique en soins rénaux pour le personnel infirmier auxiliaire. » cannt.ca, 2024." },
    ],
  },
];

