export function getFR2Post(id: string): FR2Post | undefined { return FR2_POSTS.find((p) => p.id === id); }
export function getAllFR2Topics(): FR2Topic[] { return FR2_TOPICS; }
export function getAllFR2SeoMeta() { return FR2_TOPICS.map((t) => ({ id: t.id, locale: t.locale, region: t.region, profession: t.profession, exam: t.exam, title: t.metaTitle, description: t.metaDescription, slug: t.slug })); }
